_ASSETS: dict[str, str] = {
    "input/封面.docx": ASSET_input_封面_docx,
    "thesis_md2docx/resources/hit-emblem.jpeg": ASSET_thesis_md2docx_resources_hit_emblem_jpeg,
    "thesis_md2docx/resources/hit-wordmark.png": ASSET_thesis_md2docx_resources_hit_wordmark_png,
}

def extract_asset(rel_path: str, base_dir: str) -> str | None:
    """Return the absolute path to ``rel_path`` under ``base_dir``.

    If the file does not exist, write it from the embedded base64 copy.
    Returns ``None`` if ``rel_path`` is not a known embedded asset.
    """
    data = _ASSETS.get(rel_path)
    if data is None:
        return None
    local = os.path.join(base_dir, rel_path)
    if os.path.isfile(local):
        return local
    os.makedirs(os.path.dirname(local) or ".", exist_ok=True)
    print(f"  [资源] 从 Skill 内嵌资源写出 {rel_path}…")
    with open(local, "wb") as f:
        f.write(base64.b64decode(data))
    return local

